package kotlinx.coroutines

import kotlin.test.*
import kotlin.time.*
import kotlin.time.Duration.Companion.milliseconds
import kotlin.time.Duration.Companion.nanoseconds
import kotlin.time.Duration.Companion.microseconds
import kotlin.time.Duration.Companion.days

/**
 * Test that verifies delay(Duration) properly rounds up sub-millisecond components
 * to prevent delays from returning early.
 */
class DelayDurationRoundingTest : TestBase() {

    @Test
    fun testDelayDoesNotReturnEarly() = runTest(timeout = 1.days) {
        // Test with sub-millisecond components
        val expectedDuration = 998.milliseconds + 902752.nanoseconds
        val actualDuration = measureTime { delay(expectedDuration) }
        val difference = actualDuration - expectedDuration
        // The delay should not return early
        assertTrue(difference >= Duration.ZERO, "Delay returned ${difference.absoluteValue} early")
    }

    @Test
    fun testDelayWithMicroseconds() = runTest {
        // Test with microseconds
        val expectedDuration = 100.milliseconds + 500.microseconds
        val actualDuration = measureTime { delay(expectedDuration) }
        val difference = actualDuration - expectedDuration
        assertTrue(difference >= Duration.ZERO, "Delay returned ${difference.absoluteValue} early")
    }

    @Test
    fun testDelayWithNanoseconds() = runTest {
        // Test with nanoseconds
        val expectedDuration = 50.milliseconds + 999999.nanoseconds
        val actualDuration = measureTime { delay(expectedDuration) }
        val difference = actualDuration - expectedDuration
        assertTrue(difference >= Duration.ZERO, "Delay returned ${difference.absoluteValue} early")
    }

    @Test
    fun testDelayExactMilliseconds() = runTest {
        // Test with exact milliseconds (no sub-millisecond component)
        val expectedDuration = 100.milliseconds
        val actualDuration = measureTime { delay(expectedDuration) }
        val difference = actualDuration - expectedDuration
        assertTrue(difference >= Duration.ZERO, "Delay returned ${difference.absoluteValue} early")
    }

    @Test
    fun testDelayVerySmallDuration() = runTest {
        // Test with duration less than 1ms but greater than zero
        val expectedDuration = 500.nanoseconds
        val actualDuration = measureTime { delay(expectedDuration) }
        val difference = actualDuration - expectedDuration
        // Even very small durations should not return early
        assertTrue(difference >= Duration.ZERO, "Delay returned ${difference.absoluteValue} early")
    }

    @Test
    fun testDelayOneNanosecond() = runTest {
        // Test with 1 nanosecond - should be rounded up to 1ms
        val expectedDuration = 1.nanoseconds
        val actualDuration = measureTime { delay(expectedDuration) }
        // Should delay for at least 1 nanosecond (rounded up to 1ms)
        assertTrue(actualDuration >= expectedDuration, "Delay returned early")
    }
}
"}

