package kotlinx.coroutines

import kotlin.test.*
import kotlin.time.*
import kotlin.time.Duration.Companion.milliseconds
import kotlin.time.Duration.Companion.nanoseconds
import kotlin.time.Duration.Companion.microseconds

/**
 * Unit tests for Duration.toDelayMillis() internal function to verify
 * proper rounding of sub-millisecond components.
 */
class ToDelayMillisTest : TestBase() {

    @Test
    fun testRoundUpSubMillisecondNanoseconds() {
        // 998ms + 902752ns should round up to 999ms
        val duration = 998.milliseconds + 902752.nanoseconds
        assertEquals(999L, duration.toDelayMillis())
    }

    @Test
    fun testRoundUpSubMillisecondMicroseconds() {
        // 100ms + 500us should round up to 101ms
        val duration = 100.milliseconds + 500.microseconds
        assertEquals(101L, duration.toDelayMillis())
    }

    @Test
    fun testRoundUpOneNanosecond() {
        // 50ms + 1ns should round up to 51ms
        val duration = 50.milliseconds + 1.nanoseconds
        assertEquals(51L, duration.toDelayMillis())
    }

    @Test
    fun testExactMillisecondsNoRounding() {
        // Exact 100ms should remain 100ms
        val duration = 100.milliseconds
        assertEquals(100L, duration.toDelayMillis())
    }

    @Test
    fun testOneMillisecond() {
        // Exact 1ms should remain 1ms
        val duration = 1.milliseconds
        assertEquals(1L, duration.toDelayMillis())
    }

    @Test
    fun testSubMillisecondDuration() {
        // 500ns (less than 1ms) should round up to 1ms
        val duration = 500.nanoseconds
        assertEquals(1L, duration.toDelayMillis())
    }

    @Test
    fun testOneNanosecond() {
        // 1ns should round up to 1ms (minimum positive delay)
        val duration = 1.nanoseconds
        assertEquals(1L, duration.toDelayMillis())
    }

    @Test
    fun testZeroDuration() {
        // Zero duration should return 0
        assertEquals(0L, Duration.ZERO.toDelayMillis())
    }

    @Test
    fun testNegativeDuration() {
        // Negative duration should return 0
        val duration = (-100).milliseconds
        assertEquals(0L, duration.toDelayMillis())
    }

    @Test
    fun testLargeDurationWithSubMillisecond() {
        // Large duration with sub-millisecond component
        val duration = 10000.milliseconds + 1.nanoseconds
        assertEquals(10001L, duration.toDelayMillis())
    }

    @Test
    fun testMaxSubMillisecondComponent() {
        // 999999ns (just under 1ms) added to whole milliseconds
        val duration = 5.milliseconds + 999999.nanoseconds
        assertEquals(6L, duration.toDelayMillis())
    }
}
