import kotlin.time.*
import kotlin.time.Duration.Companion.milliseconds
import kotlin.time.Duration.Companion.nanoseconds

fun Duration.toDelayMillis(): Long = if (this > Duration.ZERO) {
    val millis = inWholeMilliseconds
    // Round up if there's a sub-millisecond component
    if (millis * 1_000_000 < inWholeNanoseconds) millis + 1 else millis.coerceAtLeast(1)
} else 0

